"""Скалярный фильтр Калмана."""from __future__ import annotationsimport numpy as npfrom ..core.types import Signalfrom .base import BaseFilterclass KalmanFilter1D(BaseFilter):    name = "Фильтр Калмана (1D)"    description = "Модель случайного блуждания xₖ = xₖ₋₁ + wₖ, zₖ = xₖ + vₖ."    params_schema = {        "q":  {"type": "float", "default": 1.0e-3,               "min": 1.0e-12, "max": 1.0e6,               "label": "Шум процесса q"},        "r":  {"type": "float", "default": 1.0e-1,               "min": 1.0e-12, "max": 1.0e6,               "label": "Шум измерения r"},        "p0": {"type": "float", "default": 1.0,               "min": 1.0e-12, "max": 1.0e12,               "label": "Начальная ковариация p0"},        "x0_mode": {"type": "enum", "default": "first_sample",                    "choices": ["first_sample", "zero"],                    "label": "Начальная оценка x0"},    }    def _filter(self, x: np.ndarray, p: dict, signal: Signal) -> np.ndarray:        q = float(p["q"])        r = float(p["r"])        p_cov = float(p["p0"])        x_hat = float(x[0]) if p["x0_mode"] == "first_sample" else 0.0        y = np.empty_like(x, dtype=np.float64)        for i in range(x.size):            p_cov = p_cov + q            s = p_cov + r            k = p_cov / s            x_hat = x_hat + k * (x[i] - x_hat)            p_cov = (1.0 - k) * p_cov            y[i] = x_hat        return y